import{_ as o,o as d,c as a,a4 as i}from"./chunks/framework.4M7SpZrd.js";const h=JSON.parse('{"title":"Monitoramento Social","description":"","frontmatter":{},"headers":[],"relativePath":"admin/social-monitoring.md","filePath":"admin/social-monitoring.md"}'),t={name:"admin/social-monitoring.md"};function r(c,e,l,n,s,m){return d(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="monitoramento-social" tabindex="-1">Monitoramento Social <a class="header-anchor" href="#monitoramento-social" aria-label="Permalink to &quot;Monitoramento Social&quot;">​</a></h1><p>Gerenciamento de monitores de redes sociais e plataformas de conteudo. Cada monitor tem CRUD completo e trigger manual via admin.</p><hr><h2 id="telegram-telegram-monitor" tabindex="-1">Telegram (Telegram Monitor) <a class="header-anchor" href="#telegram-telegram-monitor" aria-label="Permalink to &quot;Telegram (Telegram Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/telegram</code></li><li><strong>File:</strong> <code>app/api/v1/admin/telegram_admin.py</code> (5 endpoints)</li><li>CRUD de canais monitorados (<code>MonitoredTelegramChannel</code>)</li><li>Campos: <code>channel_username</code>, <code>channel_id</code>, <code>is_active</code>, <code>last_scanned_at</code></li><li>Mock mode quando <code>TELEGRAM_API_ID</code> ausente</li><li>Celery Beat: <code>trigger_telegram_scan</code> a cada 10 minutos</li></ul><hr><h2 id="discord-discord-monitor" tabindex="-1">Discord (Discord Monitor) <a class="header-anchor" href="#discord-discord-monitor" aria-label="Permalink to &quot;Discord (Discord Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/discord</code></li><li><strong>File:</strong> <code>app/api/v1/admin/discord_admin.py</code> (5 endpoints)</li><li>CRUD de canais/servidores (<code>MonitoredDiscordChannel</code>)</li><li>Campos: <code>guild_id</code>, <code>channel_id</code>, <code>channel_name</code>, <code>is_active</code></li><li>Requer <code>DISCORD_BOT_TOKEN</code></li><li>Celery Beat: <code>trigger_discord_scan</code> a cada 10 minutos</li></ul><hr><h2 id="reddit-reddit-monitor" tabindex="-1">Reddit (Reddit Monitor) <a class="header-anchor" href="#reddit-reddit-monitor" aria-label="Permalink to &quot;Reddit (Reddit Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/social</code> (aba Reddit)</li><li><strong>File:</strong> <code>app/api/v1/admin/social_admin.py</code></li><li>CRUD de subreddits monitorados (<code>MonitoredSubreddit</code>)</li><li>Campos: <code>subreddit_name</code>, <code>is_active</code>, <code>last_scanned_at</code></li><li>Requer <code>REDDIT_CLIENT_ID</code>/<code>SECRET</code></li><li>Celery Beat: <code>trigger_reddit_scan</code> a cada 30 minutos</li></ul><hr><h2 id="google-alerts-alertsfeed" tabindex="-1">Google Alerts (AlertsFeed) <a class="header-anchor" href="#google-alerts-alertsfeed" aria-label="Permalink to &quot;Google Alerts (AlertsFeed)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/social</code> (aba Google Alerts)</li><li><strong>File:</strong> <code>app/api/v1/admin/social_admin.py</code></li><li>CRUD de feeds RSS (<code>GoogleAlertFeed</code>)</li><li>Campos: <code>feed_url</code>, <code>label</code>, <code>is_active</code>, <code>last_checked_at</code></li><li>Sem API key — parsing RSS publico</li><li>Celery Beat: <code>trigger_google_alerts_scan</code> a cada 1 hora</li></ul><hr><h2 id="twitter-x-x-monitor" tabindex="-1">Twitter/X (X Monitor) <a class="header-anchor" href="#twitter-x-x-monitor" aria-label="Permalink to &quot;Twitter/X (X Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/twitter</code></li><li><strong>File:</strong> <code>app/api/v1/admin/twitter_admin.py</code></li><li>CRUD de queries monitoradas (<code>MonitoredTwitterQuery</code>)</li><li>Campos: <code>query</code>, <code>is_active</code>, <code>last_scanned_at</code></li><li>Requer <code>TWITTER_BEARER_TOKEN</code> (X API v2)</li><li>Celery Beat: <code>trigger_twitter_scan</code> a cada 2 horas</li></ul><hr><h2 id="dark-web-darkweb-monitor" tabindex="-1">Dark Web (DarkWeb Monitor) <a class="header-anchor" href="#dark-web-darkweb-monitor" aria-label="Permalink to &quot;Dark Web (DarkWeb Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/darkweb</code></li><li><strong>File:</strong> <code>app/api/v1/admin/darkweb_admin.py</code> (4 endpoints)</li><li>CRUD de sites <code>.onion</code> monitorados</li><li>Requer <code>TOR_SOCKS5_PROXY</code></li><li>Celery Beat: <code>trigger_darkweb_scan</code> a cada 24 horas</li></ul><hr><h2 id="instagram-instagram-monitor" tabindex="-1">Instagram (Instagram Monitor) <a class="header-anchor" href="#instagram-instagram-monitor" aria-label="Permalink to &quot;Instagram (Instagram Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/social</code> (aba Instagram)</li><li><strong>File:</strong> <code>app/api/v1/admin/social_admin.py</code></li><li>CRUD de perfis monitorados (<code>MonitoredInstagramProfile</code>)</li><li>Campos: <code>username</code>, <code>is_active</code>, <code>last_scanned_at</code></li><li><code>INSTAGRAM_MONITOR_ENABLED</code> flag</li><li>Celery Beat: <code>trigger_instagram_scan</code> a cada 3 horas + discovery a cada 6 dias</li></ul><hr><h2 id="facebook-facebook-monitor" tabindex="-1">Facebook (Facebook Monitor) <a class="header-anchor" href="#facebook-facebook-monitor" aria-label="Permalink to &quot;Facebook (Facebook Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/social</code> (aba Facebook)</li><li>CRUD de paginas monitoradas (<code>MonitoredFacebookPage</code>)</li><li><code>DynamicFetcher</code> (Playwright) para rendering JS</li><li>Celery Beat: <code>trigger_facebook_scan</code> a cada 6 horas</li></ul><hr><h2 id="flickr-flickr-monitor" tabindex="-1">Flickr (Flickr Monitor) <a class="header-anchor" href="#flickr-flickr-monitor" aria-label="Permalink to &quot;Flickr (Flickr Monitor)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/social</code> (aba Flickr)</li><li>CRUD de queries de busca</li><li>API publica sem key</li><li>Celery Beat: <code>trigger_flickr_scan</code> a cada 12 horas</li></ul><hr><h2 id="source-discovery-sourceintel" tabindex="-1">Source Discovery (SourceIntel) <a class="header-anchor" href="#source-discovery-sourceintel" aria-label="Permalink to &quot;Source Discovery (SourceIntel)&quot;">​</a></h2><ul><li><strong>Admin page:</strong> <code>/sources</code></li><li><strong>File:</strong> <code>app/api/v1/admin/sources_admin.py</code> (10 endpoints)</li><li>Fontes descobertas automaticamente por cross-reference de links</li><li>Estados: <code>discovered</code> → <code>approved</code>/<code>rejected</code> → <code>promoted</code> (vira <code>WebCrawlerTarget</code>)</li><li><code>GET /admin/sources</code> — Lista com filtros (status, domain, risk_level)</li><li><code>PATCH /admin/sources/{id}/approve</code> — Aprovar fonte</li><li><code>PATCH /admin/sources/{id}/reject</code> — Rejeitar fonte</li><li><code>POST /admin/sources/{id}/promote</code> — Promover a alvo de crawling</li><li><code>GET /admin/sources/health</code> — Verificacao de saude das fontes ativas</li><li>Celery Beat: <code>trigger_discovery_scan</code> a cada 12h + <code>health_check_sources</code> a cada 24h</li></ul><hr><h2 id="tabela-resumo" tabindex="-1">Tabela Resumo <a class="header-anchor" href="#tabela-resumo" aria-label="Permalink to &quot;Tabela Resumo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Motor</th><th>Pagina Admin</th><th>Intervalo Celery</th><th>API Key</th></tr></thead><tbody><tr><td>Telegram</td><td><code>/telegram</code></td><td>10min</td><td><code>TELEGRAM_API_ID</code>/<code>HASH</code></td></tr><tr><td>Discord</td><td><code>/discord</code></td><td>10min</td><td><code>DISCORD_BOT_TOKEN</code></td></tr><tr><td>Reddit</td><td><code>/social</code></td><td>30min</td><td><code>REDDIT_CLIENT_ID</code>/<code>SECRET</code></td></tr><tr><td>Google Alerts</td><td><code>/social</code></td><td>1h</td><td>Nenhuma</td></tr><tr><td>Twitter/X</td><td><code>/twitter</code></td><td>2h</td><td><code>TWITTER_BEARER_TOKEN</code></td></tr><tr><td>Dark Web</td><td><code>/darkweb</code></td><td>24h</td><td><code>TOR_SOCKS5_PROXY</code></td></tr><tr><td>Instagram</td><td><code>/social</code></td><td>3h</td><td><code>INSTAGRAM_MONITOR_ENABLED</code></td></tr><tr><td>Facebook</td><td><code>/social</code></td><td>6h</td><td>Nenhuma</td></tr><tr><td>Flickr</td><td><code>/social</code></td><td>12h</td><td>Nenhuma</td></tr><tr><td>Source Discovery</td><td><code>/sources</code></td><td>12h</td><td>Nenhuma</td></tr></tbody></table>',35)])])}const u=o(t,[["render",r]]);export{h as __pageData,u as default};
